import { ChangeDetectorRef, Component, OnInit, ViewChild } from '@angular/core';
import { DataTableDirective } from 'angular-datatables';
import { Subject } from 'rxjs';
import { ApiService } from 'src/app/shared/services/api.service';
import jsPDF from 'jspdf';
import 'jspdf-autotable';
import { DatePipe } from '@angular/common';
import { AccountClosureServiceService } from 'src/app/shared/services/account-closure-service.service';
import { RoleService } from 'src/app/shared/services/role.service';
import { permissionsLabels } from 'src/app/shared/models/fmosNewRolePermissions';

@Component({
  selector: 'npr-audit-logs',
  templateUrl: './audit-logs.component.html',
  styleUrls: ['./audit-logs.component.scss']
})
export class AuditLogsComponent implements OnInit {
  isLoading:boolean = false;
  isSelected: boolean = true;
  dtOptions: DataTables.Settings = {};
  auditlogdata: any;
  pipe = new DatePipe('en-US');
  roleCodes = new permissionsLabels();

  dtTrigger: Subject<any> = new Subject<any>();

  constructor(private api: ApiService, private excelService: AccountClosureServiceService, private cdr:ChangeDetectorRef,private roleService:RoleService) { }

  ngOnInit(): void {
    this.dtOptions = {
      pagingType: 'full_numbers',
      pageLength : 5,
      processing: true,
      // columnDefs: [ { type: 'date', 'targets': [4] } ],
      // order: [[4, 'desc']],
      lengthMenu: [[5, 10, 20, -1], [5, 10, 20, 30]],
    };


    this.getAuditLogList();
    this.roleService.fetchScreenPermissions('Audit Logs');
  
    this.roleService.screenLabelList.subscribe(message => this.roleCodes = message);
    console.log(this.roleCodes);
  }

  getAuditLogList() {
    this.isLoading = true;
    this.api.getAllAuditData().subscribe((data:any) => {
      this.auditlogdata = data.result;
      this.isLoading = false;
      this.cdr.markForCheck();

      this.dtTrigger.next();
    });

  }
  modo(event) {
    console.log(event);
    if (event == 'PDF') {
      this.convert();
    }
    if (event == 'Excel') {
      this.exportAsXLSX();
    }

  }
  exportAsXLSX(): void {
    this.auditlogdata.forEach(element => {
      element.timeForExport = this.pipe.transform(element.timeForExport, 'dd-MMM-yy').toString();
      element.updatedAt = this.pipe.transform(element.updatedAt, 'dd-MMM-yy').toString();
      element.creatorDtStamp = this.pipe.transform(element.creatorDtStamp, 'dd-MMM-yy').toString();

    });
    //console.log(this.auditlogdata);
    this.excelService.exportAsExcelFile(this.auditlogdata, 'Audit_Report');
  }
  convert() {

    var doc = new jsPDF();
    var col = [["Screen", "creatorId", "ActionPerformBy", "Record", "Action", "Time"]];
    var rows = [];

    /* The following array of object as response from the API req  */

    var itemNew = this.auditlogdata;


    itemNew.forEach(element => {
      var date = new Date(element.timeForExport).toLocaleDateString("en-us");
      console.log(date)
      var temp = [element.log, element.creatorId, element.actionPerformBy, element.record, element.action, date];
      rows.push(temp);

    });

    //doc.autoTable(col, rows);
    doc.autoTable({
      head: col,
      body: rows
    });
    doc.save('AuditLog.pdf');
  }

  ngOnDestroy(): void {
    // Do not forget to unsubscribe the event
    this.dtTrigger.unsubscribe();
  }

}
